import { DcParams, Device, DeviceState, TrParams } from "../../circuit/device.js";
import { stampConductance, stampCurrentSource, Stamper } from "../../circuit/mna.js";
import type { Network, Node } from "../../circuit/network.js";
import { Properties } from "../../circuit/properties.js";
import { celsiusToKelvin } from "../../util/unit.js";
import { gMin } from "../const.js";
import { pnConductance, pnCurrent, pnTemp, pnVoltage } from "./semi.js";

const enum S {
  Is,
  N,
  Vt,
  Vcrit,
  V,
  I,
  G,
  _Size_,
}

/**
 * Diode.
 */
export class Diode extends Device {
  static override readonly id = "Diode";
  static override readonly numTerminals = 2;
  static override readonly propertiesSchema = {
    Is: Properties.number({
      defaultValue: 1e-14,
      range: ["real", ">", 0],
      title: "saturation current",
    }),
    N: Properties.number({
      defaultValue: 1,
      range: ["real", ">", 0],
      title: "emission coefficient",
    }),
    temp: Properties.temp,
  };
  static override readonly stateSchema = {
    length: S._Size_,
    ops: [
      { index: S.V, name: "V", unit: "V" },
      { index: S.I, name: "I", unit: "A" },
    ],
  };
  static override readonly linear = false;

  /** The anode terminal. */
  private na!: Node;
  /** The cathode terminal. */
  private nc!: Node;

  override connect(network: Network, [na, nc]: readonly Node[]): void {
    this.na = na;
    this.nc = nc;
  }

  override initDc(state: DeviceState, params: DcParams): void {
    const Is = this.properties.getNumber("Is");
    const N = this.properties.getNumber("N");
    const temp = celsiusToKelvin(this.properties.getNumber("temp", params.temp));
    const [Vt, Ist, Vcrit] = pnTemp(temp, Is, N);
    state[S.Is] = Ist;
    state[S.Vt] = Vt;
    state[S.Vcrit] = Vcrit;
  }

  private eval(state: DeviceState, damped: boolean): void {
    const { na, nc } = this;
    const Is = state[S.Is];
    const Vt = state[S.Vt];
    const Vcrit = state[S.Vcrit];
    let V = na.voltage - nc.voltage;
    if (damped) {
      V = pnVoltage(V, state[S.V], Vt, Vcrit);
    }
    const I = pnCurrent(V, Is, Vt);
    const G = pnConductance(V, Is, Vt) + gMin;
    state[S.V] = V;
    state[S.I] = I;
    state[S.G] = G;
  }

  override loadDc(state: DeviceState, params: DcParams, stamper: Stamper): void {
    const { na, nc } = this;
    this.eval(state, true);
    const V = state[S.V];
    const I = state[S.I];
    const G = state[S.G];
    stampConductance(stamper, na, nc, G);
    stampCurrentSource(stamper, na, nc, I - G * V);
  }

  override endDc(state: DeviceState, params: DcParams): void {
    this.eval(state, false);
  }

  override initTr(state: DeviceState, params: TrParams): void {
    this.initDc(state, params);
  }

  override loadTr(state: DeviceState, params: TrParams, stamper: Stamper): void {
    this.loadDc(state, params, stamper);
  }

  override endTr(state: DeviceState, params: TrParams): void {
    this.endDc(state, params);
  }
}
